9	/**
10	 * Operation M2 — Selective Removal.
11	 *
12	 * Given a list of upload_id values, cascades deletion through both databases:
13	 * MongoDB posts are deleted first, then the MariaDB upload record.
14	 * A failure on one upload is logged and reported but does not abort the rest.
15	 */
16	public class M2Service {
17	
18	    private static final Logger log = LoggerFactory.getLogger(M2Service.class);
19	
20	    private final MongoDao mongoDao;
21	    private final Maria_DAO mariaDao;
22	
23	    public M2Service(MongoDao mongoDao, Maria_DAO mariaDao) {
24	        this.mongoDao = mongoDao;
25	        this.mariaDao = mariaDao;
26	    }
27	
28	    public List<M2Result> execute(List<Long> uploadIds) {
29	        List<M2Result> results = new ArrayList<>();
30	
31	        for (long uploadId : uploadIds) {
32	            try {
33	                long postsDeleted = mongoDao.deletePosts(uploadId);
34	                mariaDao.deleteUpload(uploadId);
35	                log.info("M2: removed upload_id={} ({} posts deleted)", uploadId, postsDeleted);
36	                results.add(new M2Result(uploadId, postsDeleted, true, null));
37	            } catch (Exception e) {
38	                log.error("M2: failed for upload_id={} — {}", uploadId, e.getMessage(), e);
39	                results.add(new M2Result(uploadId, 0, false, e.getMessage()));
40	            }
41	        }
42	
43	        return results;
44	    }
45	}
