7	import org.slf4j.LoggerFactory;
8	
9	import java.util.ArrayList;
10	import java.util.Arrays;
11	import java.util.List;
12	import java.util.stream.Collectors;
13	
14	/**
15	 * Operation R7 — Conversation Linking.
16	 *
17	 * Given an upload_id, reconstructs threaded conversations by parsing HTML
18	 * quote-reply
19	 * relationships and building a parent-child reply tree. Each root-to-leaf path
20	 * through
21	 * the tree is returned as one R7Conversation.
22	 *
23	 * Four phases:
24	 * Phase 1 — Load posts from MongoDB
25	 * Phase 2 — Parse HTML and link each post to its parent via uplink_post_id
26	 * Phase 3 — Find root posts (no uplink, has at least one reply)
27	 * Phase 4 — Recursively build conversations from each root
28	 */
29	public class R7Service {
30	
31	    private static final Logger log = LoggerFactory.getLogger(R7Service.class);
32	    private static final int FINGERPRINT_WORDS = 20;
33	
34	    private final MongoDao mongoDao;
35	
36	    public R7Service(MongoDao mongoDao) {
37	        this.mongoDao = mongoDao;
38	    }
39	
40	    /**
41	     * Main entry point. Returns the list of all reconstructed conversations for the
42	     * given upload.
43	     */
44	    public List<R7Conversation> execute(String uploadId) {
45	        log.info("R7: Starting for upload_id={}", uploadId);
46	
47	        // Phase 1 — Load
48	        List<R7Post> posts = mongoDao.getPostsByUploadId(uploadId);
49	        if (posts.isEmpty()) {
50	            log.warn("R7: No posts found for upload_id={}", uploadId);
51	            return List.of();
52	        }
53	        log.info("R7 Phase 1 complete — {} posts loaded", posts.size());
54	
55	        // Detect obsolete uploads (pre-html collection) — html field will be null on
56	        // all posts
57	        if (posts.get(0).getHtml() == null) {
58	            log.warn("R7: upload_id={} is an obsolete upload (html field is null). " +
59	                    "These records predate html collection. Use Operation M2 to remove them.", uploadId);
60	            System.out.println("\n[R7] Sorry — upload_id " + uploadId +
61	                    " is an obsolete upload that predates HTML collection. " +
62	                    "Conversation linking is not available for this upload.\n");
63	            return List.of();
64	        }
65	
66	        // Phase 2 — Parse & Link
67	        parseAndLink(posts, uploadId);
68	        log.info("R7 Phase 2 complete — reply graph built");
69	
70	        // Phase 3 — Find Roots
71	        List<R7Post> roots = findRoots(posts);
72	        log.info("R7 Phase 3 complete — {} root(s) identified", roots.size());
73	
74	        // Phase 4 — Recursive Conversation Builder
75	        List<R7Conversation> results = new ArrayList<>();
76	        for (R7Post root : roots) {
77	            List<R7Post> path = new ArrayList<>();
78	            path.add(root);
79	            buildConversations(root, path, results, posts);
80	        }
81	        log.info("R7 Phase 4 complete — {} conversation(s) built", results.size());
82	
83	        return results;
84	    }
85	
86	    // -------------------------------------------------------------------------
87	    // Phase 2 — Parse & Link
88	    // -------------------------------------------------------------------------
89	
90	    private void parseAndLink(List<R7Post> posts, String uploadId) {
91	        for (R7Post post : posts) {
92	            if (post.getHtml() == null || post.getHtml().isBlank()) {
93	                continue;
94	            }
95	
96	            Document doc = Jsoup.parse(post.getHtml());
97	            Element outerDiv = doc.selectFirst("div.smalltext");
98	            Element innerDiv = doc.selectFirst("div.quote_colors");
99	
100	            // No quote-reply divs — standalone post or plain reply
101	            if (outerDiv == null || innerDiv == null) {
102	                continue;
103	            }
104	
105	            // Extract the quoted author from the outer div's own text
106	            String outerText = outerDiv.ownText().trim();
107	            if (!outerText.endsWith("wrote:")) {
108	                continue; // unexpected format — skip
109	            }
110	            String quotedAuthor = outerText.substring(0, outerText.length() - "wrote:".length()).trim();
111	            if (quotedAuthor.isBlank()) {
112	                log.warn("R7 Phase 2: blank quoted author in post_id={} upload_id={}", post.getPostId(), uploadId);
113	                continue;
114	            }
115	
116	            // Extract the fingerprint from the quoted text (first N words)
117	            String quotedFingerprint = fingerprint(innerDiv.text());
118	
119	            // Search for parent: same author, own-content fingerprint matches quoted
120	            // fingerprint
121	            List<R7Post> candidates = posts.stream()
122	                    .filter(p -> quotedAuthor.equals(p.getAuthor()))
123	                    .filter(p -> quotedFingerprint.equals(ownContentFingerprint(p)))
124	                    .collect(Collectors.toList());
125	
126	            if (candidates.size() == 1) {
127	                R7Post parent = candidates.get(0);
128	                post.setUplinkPostId(parent.getPostId());
129	                parent.incrementWidth();
130	            } else if (candidates.isEmpty()) {
131	                log.warn("R7 Phase 2: zero matches — post_id={}, upload_id={}, quotedAuthor={}",
132	                        post.getPostId(), uploadId, quotedAuthor);
133	            } else {
134	                log.warn("R7 Phase 2: ambiguous match ({}) — post_id={}, upload_id={}, quotedAuthor={}",
135	                        candidates.size(), post.getPostId(), uploadId, quotedAuthor);
136	            }
137	        }
138	    }
139	
140	    /**
141	     * Extracts own content from a post (excluding any nested quote div) and
142	     * returns a fingerprint of the first N words.
143	     */
144	    private String ownContentFingerprint(R7Post post) {
145	        if (post.getHtml() == null || post.getHtml().isBlank()) {
146	            return "";
147	        }
148	        Document doc = Jsoup.parse(post.getHtml());
149	        Element quoteDiv = doc.selectFirst("div.smalltext");
150	        if (quoteDiv != null) {
151	            quoteDiv.remove();
152	        }
153	        return fingerprint(doc.text());
154	    }
155	
156	    /**
157	     * Returns the first N words of the given text as a lowercase,
158	     * whitespace-normalised string.
159	     */
160	    private String fingerprint(String text) {
161	        if (text == null || text.isBlank())
162	            return "";
163	        String[] words = text.trim().split("\\s+");
164	        return Arrays.stream(words)
165	                .limit(FINGERPRINT_WORDS)
166	                .map(String::toLowerCase)
167	                .collect(Collectors.joining(" "));
168	    }
169	
170	    // -------------------------------------------------------------------------
171	    // Phase 3 — Find Roots
172	    // -------------------------------------------------------------------------
173	
174	    private List<R7Post> findRoots(List<R7Post> posts) {
175	        return posts.stream()
176	                .filter(p -> p.getUplinkPostId() == null && p.getWidth() > 0)
177	                .collect(Collectors.toList());
178	    }
179	
180	    // -------------------------------------------------------------------------
181	    // Phase 4 — Recursive Conversation Builder
182	    // -------------------------------------------------------------------------
183	
184	    private void buildConversations(R7Post current, List<R7Post> pathSoFar,
185	            List<R7Conversation> results, List<R7Post> allPosts) {
186	        List<R7Post> children = allPosts.stream()
187	                .filter(p -> current.getPostId().equals(p.getUplinkPostId()))
188	                .collect(Collectors.toList());
189	
190	        if (children.isEmpty()) {
191	            // Base case — path is complete
192	            results.add(new R7Conversation(new ArrayList<>(pathSoFar)));
193	        } else {
194	            // Recursive case — branch for each child
195	            for (R7Post child : children) {
196	                pathSoFar.add(child);
197	                buildConversations(child, pathSoFar, results, allPosts);
198	                pathSoFar.remove(pathSoFar.size() - 1);
199	            }
200	        }
201	    }
202	}
